insert into bank_questions (question_key, subject_slug, page_id, page_name, source, qtype, marks, snapshot, answer_key)
values
('computer-science:1-1-1-architecture-of-the-cpu:mcq:d0a0e221', 'computer-science', 'computer-science:1-1-1-architecture-of-the-cpu', '1.1.1 Architecture of the CPU', 'mcq', 'mcq', 1, '{"question": "What is the purpose of the CPU?", "options": ["To supply power to every other component in the case", "To render and display graphics on the monitor", "To fetch, decode and execute instructions", "To permanently store the user''s files and documents"]}'::jsonb, '{"answer": 2, "explain": "The CPU processes instructions by running the fetch–decode–execute cycle continuously. Storage, power and display are handled by other components."}'::jsonb),
('computer-science:1-1-1-architecture-of-the-cpu:mcq:f513813a', 'computer-science', 'computer-science:1-1-1-architecture-of-the-cpu', '1.1.1 Architecture of the CPU', 'mcq', 'mcq', 1, '{"question": "Put the three stages of the CPU''s cycle in the correct order.", "options": ["Decode → fetch → execute", "Fetch → execute → decode", "Execute → decode → fetch", "Fetch → decode → execute"]}'::jsonb, '{"answer": 3, "explain": "The instruction is fetched from memory first, then decoded by the control unit so the CPU knows what to do, then executed."}'::jsonb),
('computer-science:1-1-1-architecture-of-the-cpu:mcq:55c4331e', 'computer-science', 'computer-science:1-1-1-architecture-of-the-cpu', '1.1.1 Architecture of the CPU', 'mcq', 'mcq', 1, '{"question": "Which CPU component performs mathematical calculations and logical operations?", "options": ["Program counter", "Cache", "ALU", "Control unit"]}'::jsonb, '{"answer": 2, "explain": "The ALU (Arithmetic Logic Unit) does all the maths and logic — comparisons, additions, AND/OR operations. The CU coordinates; it doesn''t calculate."}'::jsonb),
('computer-science:1-1-1-architecture-of-the-cpu:mcq:519d3e94', 'computer-science', 'computer-science:1-1-1-architecture-of-the-cpu', '1.1.1 Architecture of the CPU', 'mcq', 'mcq', 1, '{"question": "Which CPU component decodes instructions and coordinates the actions of the processor?", "options": ["The ALU, which carries out calculations", "The control unit", "The MDR, which holds fetched data", "The accumulator, which stores results"]}'::jsonb, '{"answer": 1, "explain": "The control unit decodes each instruction and sends signals to synchronise and direct the other components. Remember: it directs the work, the ALU does the maths."}'::jsonb),
('computer-science:1-1-1-architecture-of-the-cpu:mcq:c363bc49', 'computer-science', 'computer-science:1-1-1-architecture-of-the-cpu', '1.1.1 Architecture of the CPU', 'mcq', 'mcq', 1, '{"question": "What does the program counter store?", "options": ["The actual data that was just fetched from memory", "The address of the next instruction to fetch", "The result of the most recent ALU calculation", "The number of programs currently open and running"]}'::jsonb, '{"answer": 1, "explain": "The PC stores the ADDRESS of the next instruction and increments each cycle. It counts nothing — despite the name."}'::jsonb),
('computer-science:1-1-1-architecture-of-the-cpu:mcq:ac7d1deb', 'computer-science', 'computer-science:1-1-1-architecture-of-the-cpu', '1.1.1 Architecture of the CPU', 'mcq', 'mcq', 1, '{"question": "Data has just been fetched from main memory. Which register is it now sitting in?", "options": ["Program counter", "MAR", "Accumulator", "MDR"]}'::jsonb, '{"answer": 3, "explain": "The MDR (Memory Data Register) holds the data or instruction just fetched from memory. The MAR held the address it came from."}'::jsonb),
('computer-science:1-1-1-architecture-of-the-cpu:mcq:9767ecc7', 'computer-science', 'computer-science:1-1-1-architecture-of-the-cpu', '1.1.1 Architecture of the CPU', 'mcq', 'mcq', 1, '{"question": "The ALU has just added two numbers. Where is the result stored?", "options": ["In the program counter", "In the MAR", "In the accumulator", "In cache"]}'::jsonb, '{"answer": 2, "explain": "The accumulator stores the results of ALU calculations. The MAR and PC only ever hold addresses."}'::jsonb),
('computer-science:1-1-1-architecture-of-the-cpu:mcq:5d66ccbf', 'computer-science', 'computer-science:1-1-1-architecture-of-the-cpu', '1.1.1 Architecture of the CPU', 'mcq', 'mcq', 1, '{"question": "Which TWO registers store addresses rather than data?", "options": ["Accumulator and program counter", "Program counter and MAR", "MAR and MDR", "MDR and accumulator"]}'::jsonb, '{"answer": 1, "explain": "PC and MAR hold locations in memory (addresses); MDR holds the data/instruction itself and the accumulator holds calculation results."}'::jsonb),
('computer-science:1-1-1-architecture-of-the-cpu:mcq:5f46b628', 'computer-science', 'computer-science:1-1-1-architecture-of-the-cpu', '1.1.1 Architecture of the CPU', 'mcq', 'mcq', 1, '{"question": "What is cache?", "options": ["Slow, large-capacity memory outside the CPU, used for long-term file storage and backups", "A single register that stores one memory address for the CPU", "The part of the CPU that performs all calculations and logic", "Small, very fast memory inside the CPU holding frequently used instructions"]}'::jsonb, '{"answer": 3, "explain": "Cache is small, very fast memory inside the CPU holding frequently used instructions and data — so the CPU avoids waiting for RAM."}'::jsonb),
('computer-science:1-1-1-architecture-of-the-cpu:mcq:1eb02bf8', 'computer-science', 'computer-science:1-1-1-architecture-of-the-cpu', '1.1.1 Architecture of the CPU', 'mcq', 'mcq', 1, '{"question": "A register is best described as...", "options": ["A tiny, very fast CPU storage location holding one value or address", "A large area of memory used to hold currently running programs and their data", "A processing unit that decodes and interprets program instructions", "A type of secondary storage used to store files permanently"]}'::jsonb, '{"answer": 0, "explain": "Registers are tiny storage locations inside the CPU — each holds a single value or address the CPU is using right now."}'::jsonb),
('computer-science:1-1-1-architecture-of-the-cpu:mcq:efd23440', 'computer-science', 'computer-science:1-1-1-architecture-of-the-cpu', '1.1.1 Architecture of the CPU', 'mcq', 'mcq', 1, '{"question": "During one fetch–execute cycle, which of these events happens?", "options": ["The program counter is incremented", "Every byte of RAM is cleared and reset", "The entire operating system reboots", "The hard drive is automatically defragmented"]}'::jsonb, '{"answer": 0, "explain": "Each cycle: an instruction is fetched, decoded, executed — and the program counter increments so the CPU knows where the next instruction is."}'::jsonb),
('computer-science:1-1-1-architecture-of-the-cpu:mcq:b2ac0635', 'computer-science', 'computer-science:1-1-1-architecture-of-the-cpu', '1.1.1 Architecture of the CPU', 'mcq', 'mcq', 1, '{"question": "Why can the CPU access an instruction in cache faster than the same instruction in RAM?", "options": ["Cache has a much larger storage capacity than RAM", "Cache sits inside the CPU, so data travels a much shorter distance", "RAM only stores data while the computer is switched off", "Instructions stored in cache have already been executed once in advance"]}'::jsonb, '{"answer": 1, "explain": "Cache sits inside the CPU and is built from faster memory, so frequently used instructions don''t have to make the slower trip from RAM."}'::jsonb),
('computer-science:1-1-1-architecture-of-the-cpu:tf:38432837', 'computer-science', 'computer-science:1-1-1-architecture-of-the-cpu', '1.1.1 Architecture of the CPU', 'tf', 'tf', 1, '{"question": "The program counter counts how many programs are currently running."}'::jsonb, '{"answer": false, "explain": "Despite its name, the PC counts nothing — it stores the ADDRESS of the next instruction to be fetched, and increments each cycle."}'::jsonb),
('computer-science:1-1-1-architecture-of-the-cpu:tf:85f94882', 'computer-science', 'computer-science:1-1-1-architecture-of-the-cpu', '1.1.1 Architecture of the CPU', 'tf', 'tf', 1, '{"question": "The MDR stores the data or instruction that has just been fetched from memory."}'::jsonb, '{"answer": true, "explain": "That''s exactly its job — the MAR says where to look in memory, and the MDR holds what was found there."}'::jsonb),
('computer-science:1-1-1-architecture-of-the-cpu:tf:811b7d89', 'computer-science', 'computer-science:1-1-1-architecture-of-the-cpu', '1.1.1 Architecture of the CPU', 'tf', 'tf', 1, '{"question": "The control unit performs all the mathematical calculations in the CPU."}'::jsonb, '{"answer": false, "explain": "Calculations and logical operations are the ALU''s job. The control unit decodes instructions and coordinates the processor."}'::jsonb),
('computer-science:1-1-1-architecture-of-the-cpu:tf:ecf587ce', 'computer-science', 'computer-science:1-1-1-architecture-of-the-cpu', '1.1.1 Architecture of the CPU', 'tf', 'tf', 1, '{"question": "Cache is a small amount of fast memory located inside the CPU."}'::jsonb, '{"answer": true, "explain": "Cache sits inside the CPU and stores frequently used instructions and data, so the CPU doesn''t have to keep fetching them from slower RAM."}'::jsonb),
('computer-science:1-1-1-architecture-of-the-cpu:tf:b7930696', 'computer-science', 'computer-science:1-1-1-architecture-of-the-cpu', '1.1.1 Architecture of the CPU', 'tf', 'tf', 1, '{"question": "The MAR stores the data that has been fetched from memory."}'::jsonb, '{"answer": false, "explain": "The MAR only ever stores an ADDRESS — the location to fetch from or write to. The data itself goes in the MDR."}'::jsonb),
('computer-science:1-1-1-architecture-of-the-cpu:tf:5ec91ae0', 'computer-science', 'computer-science:1-1-1-architecture-of-the-cpu', '1.1.1 Architecture of the CPU', 'tf', 'tf', 1, '{"question": "The accumulator stores the results of ALU calculations."}'::jsonb, '{"answer": true, "explain": "Correct — the ALU does the maths and the accumulator holds the result. Saying it stores ''the calculations'' rather than the RESULTS is a known mark-loser."}'::jsonb),
('computer-science:1-1-1-architecture-of-the-cpu:tf:dc45c24d', 'computer-science', 'computer-science:1-1-1-architecture-of-the-cpu', '1.1.1 Architecture of the CPU', 'tf', 'tf', 1, '{"question": "Registers are large stores of memory located on the motherboard."}'::jsonb, '{"answer": false, "explain": "Registers are tiny — each holds one value or address — and they are inside the CPU itself, which is why they''re the fastest storage in the computer."}'::jsonb),
('computer-science:1-1-1-architecture-of-the-cpu:tf:991d7861', 'computer-science', 'computer-science:1-1-1-architecture-of-the-cpu', '1.1.1 Architecture of the CPU', 'tf', 'tf', 1, '{"question": "The fetch–decode–execute cycle repeats continuously while the computer is running."}'::jsonb, '{"answer": true, "explain": "The CPU never stops cycling: fetch, decode, execute, increment the program counter, repeat — billions of times per second."}'::jsonb),
('computer-science:1-1-1-architecture-of-the-cpu:learn:43571494', 'computer-science', 'computer-science:1-1-1-architecture-of-the-cpu', '1.1.1 Architecture of the CPU', 'learn', 'mcq', 1, '{"readingTitle": "What is the purpose of the CPU?", "reading": "<h4>The brain that follows instructions</h4>\n<ul>\n<li>The <strong>CPU (Central Processing Unit)</strong> is the part of the computer that carries out all the processing.</li>\n<li>Its purpose is to <strong>fetch, decode and execute instructions</strong> — every program you run, from a game to a spreadsheet, is just a long list of instructions the CPU works through one at a time.</li>\n<li>Think of a chef working through a recipe: read the next step (fetch), work out what it means (decode), then do it (execute) — and repeat until the dish is finished.</li>\n</ul>\n<h4>Where the instructions come from</h4>\n<ul>\n<li>Programs and their data are stored in <strong>main memory (RAM)</strong> while they are running.</li>\n<li>The CPU constantly pulls instructions out of memory, processes them, and sends the results back — billions of times every second.</li>\n<li>This design — the program stored in memory alongside its data, with one processor working through it — is called <strong>von Neumann architecture</strong>, and it is how almost every computer works.</li>\n</ul>\n<h4>Say it the exam way</h4>\n<ul>\n<li>If a question asks for the <em>purpose</em> of the CPU, the safe two-part answer is: it <strong>processes instructions</strong> by <strong>carrying out the fetch–execute cycle</strong>.</li>\n</ul>", "question": "Which of these best states the PURPOSE of the CPU?", "options": ["It fetches, decodes and executes instructions", "It permanently stores all the user''s files and programs", "It connects the whole computer to the internet", "It displays moving images on the screen"]}'::jsonb, '{"answer": 0, "explain": "The CPU is the processor — it works through program instructions using the fetch–decode–execute cycle. Storing files is the job of storage, not the CPU."}'::jsonb),
('computer-science:1-1-1-architecture-of-the-cpu:learn:ccdbc1dc', 'computer-science', 'computer-science:1-1-1-architecture-of-the-cpu', '1.1.1 Architecture of the CPU', 'learn', 'mcq', 1, '{"readingTitle": "The fetch–decode–execute cycle", "reading": "<h4>The cycle the CPU repeats forever</h4>\n<ul>\n<li><strong>Fetch:</strong> the next instruction is copied from main memory into the CPU. The <strong>program counter</strong> holds the address of the instruction to fetch, and it <strong>increments</strong> (moves on by one) during each cycle so the CPU knows where the next instruction is.</li>\n<li><strong>Decode:</strong> the <strong>control unit</strong> works out what the instruction actually means — what operation is needed, and what data it needs.</li>\n<li><strong>Execute:</strong> the instruction is carried out — a calculation in the ALU, moving some data, or jumping to a different instruction.</li>\n<li>Then the cycle <strong>repeats</strong>, continuously, for as long as the computer is switched on.</li>\n</ul>\n<h4>Events the exam loves to ask for</h4>\n<ul>\n<li>\"Identify events that take place during the fetch–execute cycle\" is a classic question. Safe answers: an instruction is <strong>fetched from memory</strong>; the instruction is <strong>decoded</strong>; the instruction is <strong>executed</strong>; the <strong>program counter is incremented</strong>; the process <strong>repeats</strong>.</li>\n</ul>\n<h4>How fast does this happen?</h4>\n<ul>\n<li>The <strong>clock speed</strong> tells you how many cycles happen per second — a 3&nbsp;GHz CPU runs about 3 billion fetch–execute cycles every second (much more on this in 1.1.2).</li>\n</ul>", "question": "During the fetch–decode–execute cycle, what does the program counter do?", "options": ["It stores the actual data that has just been fetched from memory", "It increments each cycle to point to the next instruction", "It counts how many programs are currently open and running", "It performs the CPU''s mathematical calculations"]}'::jsonb, '{"answer": 1, "explain": "The program counter holds the ADDRESS of the next instruction and increments each cycle. It never counts programs — that''s the classic trap."}'::jsonb),
('computer-science:1-1-1-architecture-of-the-cpu:learn:49866916', 'computer-science', 'computer-science:1-1-1-architecture-of-the-cpu', '1.1.1 Architecture of the CPU', 'learn', 'mcq', 1, '{"readingTitle": "Inside the CPU: ALU, CU, cache and registers", "reading": "<h4>The four common components</h4>\n<ul>\n<li><strong>ALU (Arithmetic Logic Unit):</strong> performs the <strong>mathematical calculations</strong> (add, subtract…) and <strong>logical operations</strong> (comparisons like greater-than, AND/OR decisions).</li>\n<li><strong>CU (Control Unit):</strong> <strong>decodes instructions</strong> and sends signals to <strong>coordinate</strong> the rest of the processor — it directs the fetch–execute cycle and the flow of data. It doesn''t do the maths itself; it''s the conductor, not the orchestra.</li>\n<li><strong>Cache:</strong> a small amount of <strong>very fast memory inside the CPU</strong> that stores <strong>frequently used instructions and data</strong>, so the CPU doesn''t have to wait for the (slower) RAM every time.</li>\n<li><strong>Registers:</strong> tiny, extremely fast storage locations inside the CPU — each one holds <strong>a single piece of data or one address</strong> that the CPU is working with right now.</li>\n</ul>\n<h4>Storage sizes, smallest to biggest</h4>\n<ul>\n<li>Register (one value) → cache (small, inside the CPU) → RAM (all currently running programs). Speed goes the opposite way: registers are fastest, RAM is slowest of the three.</li>\n</ul>\n<h4>The wording that wins marks</h4>\n<ul>\n<li>Component questions are marked on precise verbs: the ALU <strong>performs</strong> calculations, the CU <strong>decodes and coordinates</strong>, cache and registers <strong>store</strong>. Mixing these up (e.g. \"the CU executes the instructions\") is the most common way to lose the mark.</li>\n</ul>", "question": "A computer program needs to check whether one number is bigger than another. Which CPU component carries out this comparison?", "options": ["The control unit", "The program counter", "The cache", "The ALU"]}'::jsonb, '{"answer": 3, "explain": "Comparisons are logical operations, and the ALU performs all mathematical calculations and logical operations. The CU decodes and coordinates; it doesn''t do the comparison itself."}'::jsonb),
('computer-science:1-1-1-architecture-of-the-cpu:learn:c9e7c67d', 'computer-science', 'computer-science:1-1-1-architecture-of-the-cpu', '1.1.1 Architecture of the CPU', 'learn', 'mcq', 1, '{"readingTitle": "Von Neumann architecture: the four registers", "reading": "<h4>The registers you must know by name</h4>\n<ul>\n<li><strong>Program counter (PC):</strong> stores the <strong>address</strong> of the <strong>next instruction</strong> to be fetched from memory. It increments during each fetch–execute cycle.</li>\n<li><strong>MAR (Memory Address Register):</strong> stores the <strong>address</strong> of the data or instruction that is about to be fetched from memory — or the address where data is about to be stored.</li>\n<li><strong>MDR (Memory Data Register):</strong> stores the actual <strong>data or instruction</strong> that has just been fetched from memory, or that is about to be written to memory.</li>\n<li><strong>Accumulator (ACC):</strong> stores the <strong>results of calculations</strong> carried out by the ALU.</li>\n</ul>\n<h4>The one distinction that decides the marks: address or data?</h4>\n<ul>\n<li>An <strong>address</strong> is the location — like a house number. <strong>Data</strong> is what''s actually stored there — like the people inside the house.</li>\n<li><strong>PC and MAR store addresses.</strong> <strong>MDR and ACC store data.</strong> If you remember only one thing from this card, make it that line.</li>\n</ul>\n<h4>A pair that works together</h4>\n<ul>\n<li>The MAR and MDR are a team: the MAR says <em>where</em> in memory to look, and the MDR holds <em>what</em> was found there. That''s why \"the MAR stores the data\" is always wrong — it only ever holds the location.</li>\n</ul>", "question": "Which pair of registers store an ADDRESS rather than data?", "options": ["MDR and MAR", "Accumulator and program counter", "Program counter and MAR", "MDR and accumulator"]}'::jsonb, '{"answer": 2, "explain": "PC and MAR hold addresses (locations in memory). The MDR holds the data/instruction itself, and the accumulator holds the results of ALU calculations."}'::jsonb),
('computer-science:1-1-1-architecture-of-the-cpu:learn:f23797b3', 'computer-science', 'computer-science:1-1-1-architecture-of-the-cpu', '1.1.1 Architecture of the CPU', 'learn', 'mcq', 1, '{"readingTitle": "Putting it together: CPU, RAM and cache in action", "reading": "<h4>What happens when you open an app</h4>\n<ul>\n<li>The program''s <strong>instructions and data are loaded into RAM</strong> (main memory) — the CPU cannot work on things directly from the hard drive or SSD.</li>\n<li>The CPU then <strong>fetches instructions from RAM</strong>, one at a time, and <strong>executes</strong> them using the fetch–decode–execute cycle.</li>\n<li>Instructions the CPU keeps coming back to are copied into <strong>cache</strong>, so next time they can be grabbed much faster than going back to RAM.</li>\n</ul>\n<h4>Why cache makes a CPU faster (the 2-mark version)</h4>\n<ul>\n<li>Cache stores frequently used instructions and data <strong>which can be accessed faster than RAM</strong> — so a bigger cache means the CPU waits less, improving performance.</li>\n<li>One subtle extra: a <em>huge</em> cache can bring diminishing returns, because it takes longer to search through more cache.</li>\n</ul>\n<h4>Answering \"describe how the CPU and RAM work together\"</h4>\n<ul>\n<li>Three-step structure: instructions/data are <strong>stored in RAM</strong> → they are <strong>fetched from RAM by the CPU</strong> → the CPU <strong>executes/processes</strong> them. Three steps, three marks.</li>\n</ul>", "question": "Why does cache memory speed up the CPU?", "options": ["It adds extra long-term storage space for the user''s own files", "It holds frequently used instructions, which load faster than from RAM", "It permanently stores a full backup copy of the entire operating system", "It physically increases the CPU''s underlying clock speed"]}'::jsonb, '{"answer": 1, "explain": "Cache holds the instructions and data the CPU uses most, inside the CPU itself — so they can be accessed far faster than going out to RAM. It doesn''t change the clock speed or store files."}'::jsonb),
('computer-science:1-1-1-architecture-of-the-cpu:misc:64456bb7', 'computer-science', 'computer-science:1-1-1-architecture-of-the-cpu', '1.1.1 Architecture of the CPU', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> The program counter keeps track of how many programs are running (or counts the instructions processed).</p><p><strong>✅ The correct idea:</strong> The program counter stores the ADDRESS of the next instruction to be fetched from memory, and it increments during each fetch–execute cycle. It is a signpost, not a tally. If your answer to any PC question doesn''t contain the word ''address'', it is almost certainly wrong.</p>", "question": "Which answer would earn the mark for ''state the purpose of the program counter''?", "options": ["It stores the address of the next instruction to fetch", "It counts the total number of fetch–execute cycles completed", "It counts how many programs are currently open", "It stores every instruction that is currently running"]}'::jsonb, '{"answer": 0, "explain": "Only the address answer scores. Counting programs or cycles is the classic misconception, and ''stores the instructions'' confuses the PC with the MDR."}'::jsonb),
('computer-science:1-1-1-architecture-of-the-cpu:misc:e3522b5d', 'computer-science', 'computer-science:1-1-1-architecture-of-the-cpu', '1.1.1 Architecture of the CPU', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> The control unit executes the instructions and does the processing itself.</p><p><strong>✅ The correct idea:</strong> The control unit DECODES instructions and sends signals to coordinate and synchronise the rest of the processor — it directs the fetch–execute cycle but doesn''t do the calculations. Weak answer: ''the CU sends signals to components'' (what for?). Strong answer: ''the CU decodes instructions and sends signals to coordinate the flow of data through the processor.'' Say what the signals achieve.</p>", "question": "Which is the BEST description of the control unit?", "options": ["It performs all the CPU''s mathematical operations directly", "It sends signals to synchronise the other components", "It decodes instructions and coordinates the processor", "It permanently stores the most frequently used program instructions"]}'::jsonb, '{"answer": 2, "explain": "Option B is the trap — it''s true but incomplete, because it only covers coordination and leaves out decoding. The full answer names decoding AND coordination."}'::jsonb),
('computer-science:1-1-1-architecture-of-the-cpu:misc:11a65f65', 'computer-science', 'computer-science:1-1-1-architecture-of-the-cpu', '1.1.1 Architecture of the CPU', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> ''The MAR fetches the data from memory'' — describing registers with action verbs.</p><p><strong>✅ The correct idea:</strong> Registers STORE; they don''t fetch, take or retrieve. Mark schemes explicitly refuse purposes written as actions. Level 0: ''the MAR fetches data''. Level 1: ''the MAR stores an address''. Full marks: ''the MAR stores the address of the data or instruction that is to be fetched from, or written to, memory.'' Always start a register''s purpose with ''stores...''.</p>", "question": "A question asks for the purpose of the MDR. Which answer style earns the mark?", "options": ["\"The MDR stores the data fetched from memory\"", "\"The MDR actively moves data around the CPU\"", "\"The MDR is just a general register in the CPU\"", "\"The MDR actively fetches data from RAM\""]}'::jsonb, '{"answer": 0, "explain": "Registers store. Answers built on fetches/moves/takes describe actions the register doesn''t perform, and ''it is a register'' just restates the question."}'::jsonb),
('computer-science:1-1-1-architecture-of-the-cpu:misc:55d4a448', 'computer-science', 'computer-science:1-1-1-architecture-of-the-cpu', '1.1.1 Architecture of the CPU', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> The MAR and the PC store data, and the MDR stores an address — they''re all much the same.</p><p><strong>✅ The correct idea:</strong> The address/data split is the whole game: PC and MAR store ADDRESSES (locations in memory); MDR and accumulator store DATA (the instruction/data itself, or a result). A typical error chain in table questions: writing MAR where PC belongs, then ''using up'' MDR on the next row too. Check the definition for the word ''address'' before you commit a register name.</p>", "question": "A definition in an exam table reads: ''Stores the address of the next instruction to be fetched. Increments during each cycle.'' Which register is it?", "options": ["Program counter (PC)", "MAR (Memory Address Register)", "MDR (Memory Data Register)", "Accumulator (ACC)"]}'::jsonb, '{"answer": 0, "explain": "''Address of the NEXT INSTRUCTION'' plus ''increments'' can only be the program counter. The MAR stores the address currently being fetched from — no incrementing."}'::jsonb),
('computer-science:1-1-1-architecture-of-the-cpu:misc:11af198a', 'computer-science', 'computer-science:1-1-1-architecture-of-the-cpu', '1.1.1 Architecture of the CPU', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> A dual-core processor is faster because it simply runs twice as many instructions per second.</p><p><strong>✅ The correct idea:</strong> The mark is for the idea of the cores working AT THE SAME TIME: each core can execute a separate instruction (or a different part of the program) simultaneously — that''s parallel processing. ''It runs more instructions per second'' on its own could just describe a faster clock. And be ready for the twist: some software can''t be split across cores, so performance doesn''t always double.</p>", "question": "Which sentence correctly explains why a dual-core CPU can improve performance?", "options": ["\"Having two cores automatically doubles the cache size\"", "\"It can process more instructions every single second\"", "\"Each core runs a separate instruction simultaneously\"", "\"Two cores always double the CPU''s clock speed\""]}'::jsonb, '{"answer": 2, "explain": "The winning idea is simultaneous execution — parallel processing. Doubling clock speed or cache isn''t what a second core does, and ''more instructions per second'' misses the ''at the same time'' requirement."}'::jsonb),
('computer-science:1-1-1-architecture-of-the-cpu:tips:509ebf41', 'computer-science', 'computer-science:1-1-1-architecture-of-the-cpu', '1.1.1 Architecture of the CPU', 'tips', 'mcq', 1, '{"readingTitle": "explain — Register questions: from 0 to full marks", "reading": "<p>Here is the same answer to <em>\"State the purpose of the MAR\"</em> at every level:</p>\n\n<p><strong>❌ 0 marks:</strong> \"The MAR is a register inside the CPU.\"</p>\n<ul>\n<li>True, but it just restates the question — no purpose given.</li>\n</ul>\n\n<p><strong>❌ 0 marks:</strong> \"The MAR fetches the data from memory.\"</p>\n<ul>\n<li>Registers <strong>store</strong> — purposes written as actions (fetches, takes, retrieves) are refused.</li>\n</ul>\n\n<p><strong>⚠️ Borderline:</strong> \"The MAR stores an address.\"</p>\n<ul>\n<li>The verb is right, but WHICH address? Too vague to be safe.</li>\n</ul>\n\n<p><strong>✅ Full marks:</strong> \"The MAR stores the address of the data or instruction that is to be fetched from, or written to, memory.\"</p>\n\n<p><strong>The pattern for all four registers:</strong> \"Stores the…\" + address or data + what it belongs to:</p>\n<ul>\n<li>PC → stores the <strong>address of the next instruction</strong> to be fetched (and increments each cycle)</li>\n<li>MAR → stores the <strong>address</strong> of the data/instruction being fetched or written</li>\n<li>MDR → stores the <strong>data/instruction</strong> fetched from memory</li>\n<li>ACC → stores the <strong>results</strong> of ALU calculations</li>\n</ul>", "question": "Why does \"the MAR fetches data from memory\" score 0?", "options": ["The MAR does not actually exist as a real CPU register", "The answer given is simply too short for the mark", "Registers STORE data — describing them as performing an action is wrong", "Register names must always be spelled out in full rather than abbreviated like MAR"]}'::jsonb, '{"answer": 2, "explain": "Registers are storage locations. The fetching is done by the CPU as a whole during the cycle — the register just holds the address or data involved."}'::jsonb),
('computer-science:1-1-1-architecture-of-the-cpu:tips:ef7572cb', 'computer-science', 'computer-science:1-1-1-architecture-of-the-cpu', '1.1.1 Architecture of the CPU', 'tips', 'mcq', 1, '{"readingTitle": "explain — 2-mark ''explain why it''s faster'' questions: the …which means… chain", "reading": "<p>Performance explanations (clock speed, cache, cores) are marked as <strong>point + development</strong>. One fact = 1 mark; linking it to performance = the 2nd mark.</p>\n\n<p><strong>Example: \"Explain why a 3.2 GHz CPU usually runs faster than a 1.2 GHz CPU.\" [2]</strong></p>\n\n<p><strong>⚠️ 1 mark:</strong> \"3.2 GHz is a higher clock speed.\"</p>\n<ul>\n<li>Correct point, no development — the chain stops.</li>\n</ul>\n\n<p><strong>✅ 2 marks:</strong> \"3.2 GHz is a higher clock speed, so it runs more fetch–execute cycles per second, <strong>which means</strong> more instructions can be executed per second.\"</p>\n\n<p><strong>The same chain works for cache:</strong> \"Cache stores frequently used instructions → they can be accessed faster than from RAM → so the CPU spends less time waiting.\"</p>\n\n<p><strong>Two traps:</strong></p>\n<ul>\n<li>\"Cache is faster than RAM\" alone scores nothing — faster at <em>what</em>? Name the access to instructions/data.</li>\n<li>For dual core, the development must include <strong>at the same time</strong> (parallel execution) — \"more instructions per second\" alone reads like clock speed.</li>\n</ul>", "question": "\"More cache improves performance\" scores 1 out of 2. What''s missing?", "options": ["The specific brand and full model name of the CPU", "A fully labelled diagram showing every one of the CPU''s components", "The precise size of the cache, given exactly in megabytes or gigabytes", "The chain: cache stores instructions accessible faster than RAM"]}'::jsonb, '{"answer": 3, "explain": "The second mark is for developing the point: WHAT cache stores and WHY that speeds things up (faster access than RAM). Assertions about performance without the mechanism stay on 1 mark."}'::jsonb),
('computer-science:1-1-1-architecture-of-the-cpu:tips:b824f0a6', 'computer-science', 'computer-science:1-1-1-architecture-of-the-cpu', '1.1.1 Architecture of the CPU', 'tips', 'mcq', 1, '{"readingTitle": "tip — Table and matching questions: play them like a puzzle", "reading": "<p>1.1.1 is full of table-completion and match-the-definition questions. Technique matters as much as knowledge:</p>\n\n<p><strong>1. Scan the whole table before writing anything.</strong></p>\n<ul>\n<li>A classic error chain: writing MAR in the row that should be PC, then forcing MDR into the MAR row — one early slip wrecks three rows. Pencil in all rows mentally first.</li>\n</ul>\n\n<p><strong>2. Use the address/data keyword test.</strong></p>\n<ul>\n<li>Definition contains \"address of the next instruction\" + \"increments\" → PC. \"Address\" of data being fetched/stored → MAR. \"Data/instruction fetched\" → MDR. \"Result\" → accumulator. \"Calculations/logical operations\" → ALU. \"Coordinates/decodes/signals\" → CU.</li>\n</ul>\n\n<p><strong>3. In draw-one-line matching, count the boxes.</strong></p>\n<ul>\n<li>If there are more definitions than components, at least one definition is a decoy — expect something plausible-sounding like \"keeps the clock in sync\".</li>\n<li>Drawing two lines from one component scores 0 for that component. One from, one to.</li>\n</ul>\n\n<p><strong>4. In tick-grids, extra ticks kill the row.</strong></p>\n<ul>\n<li>Each row is marked as a whole: the correct ticks AND no extras. If unsure, tick only what you''re confident in — a stray extra tick turns a right answer into 0 for that row.</li>\n</ul>", "question": "In a tick-grid question, a student ticks the two correct boxes in a row PLUS one extra box. What happens?", "options": ["The examiner simply ignores the extra tick mark", "They still receive partial credit of 2 out of 3 for the row", "They score 0 for that row — extra ticks void it", "They simply lose 1 mark from their overall total"]}'::jsonb, '{"answer": 2, "explain": "Rows are all-or-nothing: right ticks with any extra tick scores 0 for that row. Tick with intent, not with hope."}'::jsonb),
('computer-science:1-1-1-architecture-of-the-cpu:fib:60773e51', 'computer-science', 'computer-science:1-1-1-architecture-of-the-cpu', '1.1.1 Architecture of the CPU', 'fib', 'fib', 2, '{"question": "The CPU''s purpose is to _____, decode and _____ instructions.", "blankOptions": {"B1": ["frequently", "results", "fetch", "ALU"], "B2": ["execute", "results", "increments", "RAM"]}}'::jsonb, '{"blanks": {"B1": "fetch", "B2": "execute"}}'::jsonb),
