('computer-science:1-1-1-architecture-of-the-cpu:match:02f4ed45', 'computer-science', 'computer-science:1-1-1-architecture-of-the-cpu', '1.1.1 Architecture of the CPU', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “CPU”?", "options": ["Stores the address of the data or instruction to be fetched from or written to memory", "Performs mathematical calculations and logical operations", "The component that processes instructions by carrying out the fetch–execute cycle", "Decodes instructions and coordinates the actions of the processor"]}'::jsonb, '{"answer": 2, "explain": "“CPU” means: The component that processes instructions by carrying out the fetch–execute cycle"}'::jsonb),
('computer-science:1-1-1-architecture-of-the-cpu:match:f7ad3e9a', 'computer-science', 'computer-science:1-1-1-architecture-of-the-cpu', '1.1.1 Architecture of the CPU', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Fetch”?", "options": ["A tiny, very fast storage location inside the CPU holding a single value or address", "Stores the address of the data or instruction to be fetched from or written to memory", "The stage where the next instruction is copied from main memory into the CPU", "The component that processes instructions by carrying out the fetch–execute cycle"]}'::jsonb, '{"answer": 2, "explain": "“Fetch” means: The stage where the next instruction is copied from main memory into the CPU"}'::jsonb),
('computer-science:1-1-1-architecture-of-the-cpu:match:a2a58076', 'computer-science', 'computer-science:1-1-1-architecture-of-the-cpu', '1.1.1 Architecture of the CPU', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Decode”?", "options": ["The stage where the instruction is actually carried out", "The stage where the control unit works out what an instruction means", "Small, fast memory inside the CPU storing frequently used instructions and data", "The component that processes instructions by carrying out the fetch–execute cycle"]}'::jsonb, '{"answer": 1, "explain": "“Decode” means: The stage where the control unit works out what an instruction means"}'::jsonb),
('computer-science:1-1-1-architecture-of-the-cpu:match:905896ac', 'computer-science', 'computer-science:1-1-1-architecture-of-the-cpu', '1.1.1 Architecture of the CPU', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Execute”?", "options": ["The stage where the instruction is actually carried out", "The component that processes instructions by carrying out the fetch–execute cycle", "Decodes instructions and coordinates the actions of the processor", "Performs mathematical calculations and logical operations"]}'::jsonb, '{"answer": 0, "explain": "“Execute” means: The stage where the instruction is actually carried out"}'::jsonb),
('computer-science:1-1-1-architecture-of-the-cpu:match:635b1dc7', 'computer-science', 'computer-science:1-1-1-architecture-of-the-cpu', '1.1.1 Architecture of the CPU', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “ALU”?", "options": ["Stores the results of calculations carried out by the ALU", "Performs mathematical calculations and logical operations", "Small, fast memory inside the CPU storing frequently used instructions and data", "Stores the data or instruction that has just been fetched from (or is being written to) memory"]}'::jsonb, '{"answer": 1, "explain": "“ALU” means: Performs mathematical calculations and logical operations"}'::jsonb),
