('computer-science:1-1-1-architecture-of-the-cpu:match:430a2d66', 'computer-science', 'computer-science:1-1-1-architecture-of-the-cpu', '1.1.1 Architecture of the CPU', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Cache”?", "options": ["A tiny, very fast storage location inside the CPU holding a single value or address", "Stores the address of the data or instruction to be fetched from or written to memory", "Small, fast memory inside the CPU storing frequently used instructions and data", "Stores the address of the next instruction to be fetched; increments each cycle"]}'::jsonb, '{"answer": 2, "explain": "“Cache” means: Small, fast memory inside the CPU storing frequently used instructions and data"}'::jsonb),
('computer-science:1-1-1-architecture-of-the-cpu:match:5fce3862', 'computer-science', 'computer-science:1-1-1-architecture-of-the-cpu', '1.1.1 Architecture of the CPU', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Register”?", "options": ["The component that processes instructions by carrying out the fetch–execute cycle", "Small, fast memory inside the CPU storing frequently used instructions and data", "A tiny, very fast storage location inside the CPU holding a single value or address", "Decodes instructions and coordinates the actions of the processor"]}'::jsonb, '{"answer": 2, "explain": "“Register” means: A tiny, very fast storage location inside the CPU holding a single value or address"}'::jsonb),
