('computer-science:1-1-2-cpu-performance:match:31f47c95', 'computer-science', 'computer-science:1-1-2-cpu-performance', '1.1.2 CPU Performance', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Clock speed”?", "options": ["Volatile memory holding the programs and data currently running", "Faster read/write speeds than a hard disk drive, so programs load quicker", "The number of fetch–execute cycles the CPU carries out per second", "Non-volatile memory holding the boot-up instructions (BIOS)"]}'::jsonb, '{"answer": 2, "explain": "“Clock speed” means: The number of fetch–execute cycles the CPU carries out per second"}'::jsonb),
