('computer-science:1-1-2-cpu-performance:match:0c144bbf', 'computer-science', 'computer-science:1-1-2-cpu-performance', '1.1.2 CPU Performance', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Gigahertz (GHz)”?", "options": ["Volatile memory holding the programs and data currently running", "A processing unit that can run its own fetch–execute cycle", "Billions of fetch–execute cycles per second", "More frequently used instructions held close to the CPU, so fewer slow trips to RAM"]}'::jsonb, '{"answer": 2, "explain": "“Gigahertz (GHz)” means: Billions of fetch–execute cycles per second"}'::jsonb),
('computer-science:1-1-2-cpu-performance:match:bc06b20b', 'computer-science', 'computer-science:1-1-2-cpu-performance', '1.1.2 CPU Performance', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Cache”?", "options": ["Several cores each executing a separate instruction simultaneously", "Non-volatile memory holding the boot-up instructions (BIOS)", "More frequently used instructions held close to the CPU, so fewer slow trips to RAM", "Small, very fast memory inside the CPU holding frequently used instructions and data"]}'::jsonb, '{"answer": 3, "explain": "“Cache” means: Small, very fast memory inside the CPU holding frequently used instructions and data"}'::jsonb)
